CREATE OR REPLACE FUNCTION fpb_get_bank_name (as_bank_code char ) RETURNS varchar AS $body$
DECLARE

ls_bank_name sc_acc_m_ucf_bank.bank_name%type;

BEGIN
  SELECT sc_acc_m_ucf_bank.bank_name
  INTO STRICT ls_bank_name
  FROM sc_acc_m_ucf_bank
  WHERE sc_acc_m_ucf_bank.bank_id =  as_bank_code;
  if coalesce(ls_bank_name::text, '') = '' then ls_bank_name := as_bank_code;end if;
  return ls_bank_name;

END;
$body$
